from flask import Flask, request, jsonify
from sklearn.linear_model import LogisticRegression
from sklearn.model_selection import train_test_split
from nltk.corpus import stopwords
from nltk.tokenize import word_tokenize
import pandas as pd
import pickle

app = Flask(__name__)

# Load preprocessed data (assuming it's a pandas DataFrame with 'text' and 'label' columns)
data = pd.read_csv('preprocessed_emails.csv')

# Define stopwords
stop_words = set(stopwords.words('english'))

# Tokenize, remove stop words and convert to frequency
def preprocess(text):
    tokens = word_tokenize(str(text).lower())
    filtered_tokens = [token for token in tokens if token not in stop_words]
    return {token: filtered_tokens.count(token) for token in set(filtered_tokens)}

# Split data into training and testing sets
X_train, X_test, y_train, y_test = train_test_split(data['text'].apply(preprocess), data['label'], test_size=0.2)

# Train the logistic regression model
model = LogisticRegression()
model.fit(X_train, y_train)

@app.route('/predict', methods=['POST'])
def predict():
    data = request.get_json()
    text = preprocess(data.get('text'))
    proba = model.predict_proba([text])[0][1]
    return jsonify({'spam_probability': proba})

if __name__ == '__main__':
    app.run(debug=True)